// Send player and winner data (after round winner is decided)
export async function sendPlayerAndWinnerDataToCaptivate(gameState, roundData) {
  console.log('🏆 sendPlayerAndWinnerDataToCaptivate called with:', { gameState: !!gameState, roundData: !!roundData });

  const player1 = gameState.player1 || {};
  const player2 = gameState.player2 || {};

  // Calculate scores from all completed rounds
  let player1TotalScore = 0;
  let player2TotalScore = 0;

  if (gameState.rounds) {
    gameState.rounds.forEach(round => {
      if (round.winner === 'player1') {
        player1TotalScore++;
      } else if (round.winner === 'player2') {
        player2TotalScore++;
      }
    });
  }

  const variables = {
    // Player scores
    player1_name: `${player1.firstName || ''} ${player1.lastName || ''}`.trim() || 'Player 1',
    player1_handle: player1.handle || '@unknown',
    player1_platform: player1.platform || '',
    player1_avatarUrl: player1.avatarUrl || '',
    player1_aura: player1TotalScore || 0,
    player1_skill: player1TotalScore || 0, // Using score for both for compatibility

    player2_name: `${player2.firstName || ''} ${player2.lastName || ''}`.trim() || 'Player 2',
    player2_handle: player2.handle || '@unknown', 
    player2_platform: player2.platform || '',
    player2_avatarUrl: player2.avatarUrl || '',
    player2_aura: player2TotalScore || 0,
    player2_skill: player2TotalScore || 0, // Using score for both for compatibility
  };

  // Add winner-specific data if round is provided
  if (roundData) {
    const winnerCard = roundData.winner === 'player1' ? roundData.C1 : roundData.C2;
    if (winnerCard) {
      const winnerUrls = getCardImageUrls(winnerCard);
      variables.winner_character = winnerCard.character || '';
      variables.winner_rarity = winnerCard.rarity || '';
      variables.winner_imageUrl = winnerUrls.card_imageUrl || '';
      variables.winner_characterUrl = winnerUrls.card_characterUrl || '';
      variables.winner_color = getColorForRarity(winnerCard.rarity);
    }
  }

  console.log('🏆 About to send winner/player variables to specific templates:', variables);

  try {
    const { ServiceHandler } = await import('./servicehandler.mjs');

    if (!ServiceHandler.scheduler) {
      console.warn('ServiceHandler scheduler not available for winner updates');
      return null;
    }

    // ONLY target winner-specific templates - NOT all graphics
    const winnerTemplateNames = [
      'Winner Stinger',
      'Card C', 
      'Character C',
      'Player 1 Score',
      'Player 2 Score'
    ];

    console.log('🏆 Templates to send winner UPDATE commands to:', winnerTemplateNames);

    // Send UPDATE command to each winner template
    const updateResults = [];

    for (const templateName of winnerTemplateNames) {
      try {
        console.log(`🏆 Sending UPDATE command to winner template: ${templateName}`);

        const result = await ServiceHandler.scheduler.scheduleAction('update', ServiceHandler.inputName, templateName, variables);
        updateResults.push({ template: templateName, result });

        console.log(`✅ Winner UPDATE command sent to ${templateName}:`, result);
      } catch (error) {
        console.error(`❌ Failed to send winner UPDATE to ${templateName}:`, error);
        updateResults.push({ template: templateName, error: error.message });
      }
    }

    console.log('🏆 All winner UPDATE results:', updateResults);
    return updateResults;

  } catch (error) {
    console.error('🔴 Failed to send winner update commands:', error);
    return null;
  }
}

