// Combined function to send both current and next round data
export async function sendBothRoundsDataToCaptivate(currentRound, nextRound, gameState = null) {
  const startTime = Date.now();
  console.log(`[TIMING ${new Date().toISOString()}] 🔄 sendBothRoundsDataToCaptivate ENTRY`, { 
    currentRound: !!currentRound, 
    nextRound: !!nextRound,
    gameState: !!gameState 
  });

  const results = {};

  // STEP 1: Send UPDATE commands first (current round data)
  if (currentRound) {
    const currentStartTime = Date.now();
    console.log(`[TIMING ${new Date().toISOString()}] 📤 About to send UPDATE commands...`);

    try {
      results.current = await sendCurrentRoundDataToCaptivate(currentRound);
      const currentTime = Date.now() - currentStartTime;
      console.log(`[TIMING ${new Date().toISOString()}] ✅ UPDATE commands completed in ${currentTime}ms:`, results.current);
    } catch (error) {
      const currentTime = Date.now() - currentStartTime;
      console.log(`[TIMING ${new Date().toISOString()}] ❌ UPDATE commands FAILED after ${currentTime}ms:`, error);
    }
  } else {
    console.log(`[TIMING ${new Date().toISOString()}] ⚠️ No current round data to send`);
  }

  // STEP 2: Wait 2 seconds before sending render commands
  console.log(`[TIMING ${new Date().toISOString()}] ⏳ Waiting 2 seconds before sending render commands...`);
  await new Promise(resolve => setTimeout(resolve, 2000));
  console.log(`[TIMING ${new Date().toISOString()}] ⏳ Wait completed, proceeding with render commands...`);

  // STEP 3: Send RENDER commands (next round data) 
  // If no next round provided, try to generate it by peeking
  let nextRoundToSend = nextRound;
  if (!nextRoundToSend && gameState) {
    const peekStartTime = Date.now();
    console.log(`[TIMING ${new Date().toISOString()}] 👀 About to peek for next round...`);

    nextRoundToSend = await generateNextRoundDataByPeeking(gameState);

    const peekTime = Date.now() - peekStartTime;
    console.log(`[TIMING ${new Date().toISOString()}] 👀 Peeking completed in ${peekTime}ms`);
  }

  if (nextRoundToSend) {
    const renderStartTime = Date.now();
    console.log(`[TIMING ${new Date().toISOString()}] 📤 About to send RENDER commands...`);

    try {
      results.next = await sendNextRoundDataToCaptivate(nextRoundToSend);
      const renderTime = Date.now() - renderStartTime;
      console.log(`[TIMING ${new Date().toISOString()}] ✅ RENDER commands completed in ${renderTime}ms:`, results.next);
    } catch (error) {
      const renderTime = Date.now() - renderStartTime;
      console.log(`[TIMING ${new Date().toISOString()}] ❌ RENDER commands FAILED after ${renderTime}ms:`, error);
    }
  } else {
    console.log(`[TIMING ${new Date().toISOString()}] ⚠️ No next round data to send`);
  }

  const totalTime = Date.now() - startTime;
  console.log(`[TIMING ${new Date().toISOString()}] 🔄 sendBothRoundsDataToCaptivate COMPLETED in ${totalTime}ms`);
  return results;
}
